const rows = $input.all();
const config = {};
for (const r of rows) config[r.json.key] = r.json.value;
const neo4j_auth = 'Basic ' + Buffer.from(config.neo4j_user + ':' + config.neo4j_password).toString('base64');
return [{ json: { config, neo4j_auth } }];

