={{ [
  {"statement": "MATCH (c:Company) RETURN count(c) as total_companies"},
  {"statement": "MATCH ()-[r]->() RETURN type(r) as rel_type, count(r) as count ORDER BY count DESC"},
  {"statement": "MATCH (c:Company) WHERE c.sanctions_hit = true RETURN c.name as name, c.country as country, c.risk_level as risk_level"},
  {"statement": "MATCH (c:Company)-[r]->() WITH c, count(r) as connections ORDER BY connections DESC LIMIT 10 RETURN c.name as name, c.country as country, c.confidence as confidence, connections"},
  {"statement": "MATCH (c:Company) WHERE c.confidence IS NOT NULL AND c.confidence < 0.6 RETURN count(c) as uncertain_count"},
  {"statement": "MATCH (c:Company) WHERE c.tier IS NOT NULL RETURN c.tier as tier, count(c) as count ORDER BY tier"}
] }}

