const neo4j_resp = $('Fetch Graph Stats').first().json;
const pg = $('Fetch PG Stats').first().json;
const date = new Date().toISOString().split('T')[0];

const results = neo4j_resp?.results || [];
const total_companies = results[0]?.data?.[0]?.row?.[0] || 0;
const rel_types = (results[1]?.data || []).map(d => ({ type: d.row[0], count: d.row[1] }));
const sanctioned = (results[2]?.data || []).map(d => ({ name: d.row[0], country: d.row[1], risk: d.row[2] }));
const top_nodes = (results[3]?.data || []).map(d => ({ name: d.row[0], country: d.row[1], confidence: d.row[2], connections: d.row[3] }));
const uncertain_count = results[4]?.data?.[0]?.row?.[0] || 0;
const by_tier = (results[5]?.data || []).map(d => ({ tier: d.row[0], count: d.row[1] }));

const rel_summary = rel_types.map(r => `${r.type}: ${r.count}`).join(', ');
const tier_summary = by_tier.map(t => `Tier ${t.tier}: ${t.count}`).join(' | ');

const top_nodes_rows = top_nodes.map(n => {
  const conf_color = n.confidence >= 0.8 ? '#22c55e' : n.confidence >= 0.6 ? '#f59e0b' : '#ef4444';
  return `<tr><td>${n.name}</td><td>${n.country || '?'}</td><td><span style="color:${conf_color}">${(n.confidence || 0).toFixed(2)}</span></td><td>${n.connections}</td></tr>`;
}).join('');

const sanctioned_rows = sanctioned.map(s => `<tr><td style="color:#ef4444;font-weight:bold">${s.name}</td><td>${s.country || '?'}</td><td>${s.risk || '?'}</td></tr>`).join('');

const html = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><title>SupplyLens Report ${date}</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:system-ui,sans-serif;background:#0f172a;color:#e2e8f0;padding:24px}h1{font-size:22px;font-weight:700;color:#60a5fa;margin-bottom:4px}h2{font-size:13px;font-weight:600;text-transform:uppercase;letter-spacing:.5px;color:#94a3b8;margin:20px 0 10px}.date{color:#64748b;font-size:13px;margin-bottom:24px}.cards{display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:12px;margin-bottom:24px}.card{background:#1e293b;border-radius:10px;padding:16px;border:1px solid #334155}.card .num{font-size:28px;font-weight:700}.card .lbl{font-size:11px;color:#64748b;margin-top:2px}table{width:100%;border-collapse:collapse;background:#1e293b;border-radius:10px;border:1px solid #334155;overflow:hidden}th{background:#0f172a;font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:.5px;padding:8px 12px;text-align:left;color:#94a3b8}td{padding:8px 12px;font-size:13px;border-top:1px solid #1e293b}.section{margin-bottom:24px}</style></head><body><h1>SupplyLens — Supply Chain Graph Report</h1><div class="date">${date} — KnopenKoning</div><div class="cards"><div class="card"><div class="num" style="color:#60a5fa">${total_companies}</div><div class="lbl">Companies mapped</div></div><div class="card"><div class="num" style="color:#f59e0b">${uncertain_count}</div><div class="lbl">Low confidence (&lt;0.60)</div></div><div class="card"><div class="num" style="color:#ef4444">${sanctioned.length}</div><div class="lbl">Sanctions hits</div></div><div class="card"><div class="num" style="color:#22c55e">${pg.accepted || 0}</div><div class="lbl">Claims accepted</div></div><div class="card"><div class="num">${pg.contested || 0}</div><div class="lbl">Contested claims</div></div><div class="card"><div class="num">${pg.avg_confidence || '—'}</div><div class="lbl">Avg confidence</div></div></div><div class="section"><h2>Tier Distribution</h2><p style="color:#94a3b8;font-size:13px;margin-top:8px">${tier_summary || 'No tiers yet'}</p></div><div class="section"><h2>Relationship Types</h2><p style="color:#94a3b8;font-size:13px;margin-top:8px">${rel_summary || 'None yet'}</p></div>${sanctioned.length > 0 ? `<div class="section"><h2 style="color:#ef4444">Sanctions Alerts</h2><table><tr><th>Company</th><th>Country</th><th>Risk Level</th></tr>${sanctioned_rows}</table></div>` : ''}<div class="section"><h2>Most Connected Nodes (Hub Companies)</h2><table><tr><th>Company</th><th>Country</th><th>Confidence</th><th>Connections</th></tr>${top_nodes_rows || '<tr><td colspan="4" style="color:#64748b">No data yet</td></tr>'}</table></div></body></html>`;

const md = `# SupplyLens Weekly Report — ${date}\n\n**Companies mapped:** ${total_companies} | **Sanctions hits:** ${sanctioned.length} | **Avg confidence:** ${pg.avg_confidence || 'n/a'}\n\n## Tier Distribution\n${tier_summary || 'No data'}\n\n## Claims Pipeline\n- Accepted: ${pg.accepted} | Rejected: ${pg.rejected} | Needs review: ${pg.needs_review} | Pending: ${pg.pending}\n- Contested: ${pg.contested}\n\n## Top Hub Companies\n| Company | Country | Confidence | Connections |\n|---------|---------|-----------|------------|\n${top_nodes.map(n => `| ${n.name} | ${n.country || '?'} | ${(n.confidence||0).toFixed(2)} | ${n.connections} |`).join('\n')}\n\n${sanctioned.length > 0 ? `## Sanctions Alerts\n${sanctioned.map(s => `- **${s.name}** (${s.country}) — ${s.risk}`).join('\n')}` : ''}`;

const ts = new Date().toISOString().replace(/[:.T]/g, '-').slice(0, 19);
return [{ json: { html, md, date, ts } }];

const d = $input.first().json;
// Only HTML - MD causes git race condition on push
return [
  { json: { content_b64: Buffer.from(d.html).toString('base64'), type: 'html', date: d.date, ts: d.ts } }
];
